import React, { useState, useRef, useEffect } from 'react';
import {
  View,
  StyleSheet,
  TouchableOpacity,
  TextInput,
  ScrollView,
  Animated,
  Dimensions,
  KeyboardAvoidingView,
  Platform,
  ActivityIndicator,
} from 'react-native';
import { Text } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import { sendMessageToGemini, resetConversation } from '../services/geminiApi';

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');
const CHAT_WIDTH = Math.min(380, SCREEN_WIDTH - 32);
const CHAT_HEIGHT = Math.min(520, SCREEN_HEIGHT - 160);

export default function GeminiChatbot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      id: '1',
      text: 'Hi there! 🌱 I\'m your Farm2Table Assistant. Ask me anything about fresh produce, orders, farming tips, or navigating the app!',
      isBot: true,
      timestamp: new Date(),
    },
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const slideAnim = useRef(new Animated.Value(0)).current;
  const fabScale = useRef(new Animated.Value(1)).current;
  const pulseAnim = useRef(new Animated.Value(1)).current;
  const scrollViewRef = useRef(null);

  // Pulse animation for the FAB
  useEffect(() => {
    const pulse = Animated.loop(
      Animated.sequence([
        Animated.timing(pulseAnim, { toValue: 1.15, duration: 1200, useNativeDriver: true }),
        Animated.timing(pulseAnim, { toValue: 1, duration: 1200, useNativeDriver: true }),
      ])
    );
    pulse.start();
    return () => pulse.stop();
  }, []);

  const toggleChat = () => {
    const toValue = isOpen ? 0 : 1;
    Animated.spring(slideAnim, {
      toValue,
      tension: 65,
      friction: 10,
      useNativeDriver: true,
    }).start();

    Animated.sequence([
      Animated.timing(fabScale, { toValue: 0.8, duration: 100, useNativeDriver: true }),
      Animated.spring(fabScale, { toValue: 1, tension: 200, friction: 10, useNativeDriver: true }),
    ]).start();

    setIsOpen(!isOpen);
  };

  const handleSend = async () => {
    if (!inputText.trim() || isLoading) return;

    const userMsg = {
      id: Date.now().toString(),
      text: inputText.trim(),
      isBot: false,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);

    setTimeout(() => scrollViewRef.current?.scrollToEnd({ animated: true }), 100);

    try {
      const response = await sendMessageToGemini(userMsg.text);
      const botMsg = {
        id: (Date.now() + 1).toString(),
        text: response,
        isBot: true,
        timestamp: new Date(),
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      const errorMsg = {
        id: (Date.now() + 1).toString(),
        text: 'Oops! Something went wrong. Please check your API key or try again later. 😔',
        isBot: true,
        isError: true,
        timestamp: new Date(),
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
      setTimeout(() => scrollViewRef.current?.scrollToEnd({ animated: true }), 100);
    }
  };

  const handleClearChat = () => {
    resetConversation();
    setMessages([
      {
        id: Date.now().toString(),
        text: 'Chat cleared! 🌱 How can I help you today?',
        isBot: true,
        timestamp: new Date(),
      },
    ]);
  };

  const quickReplies = [
    '🥬 What\'s in season?',
    '🚚 Track my order',
    '👨‍🌾 Find local farmers',
    '💡 Farming tips',
  ];

  const chatTranslateY = slideAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [CHAT_HEIGHT + 50, 0],
  });

  const chatOpacity = slideAnim.interpolate({
    inputRange: [0, 0.5, 1],
    outputRange: [0, 0.8, 1],
  });

  const overlayOpacity = slideAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [0, 0.3],
  });

  return (
    <View style={styles.container} pointerEvents="box-none">
      {/* Backdrop overlay */}
      {isOpen && (
        <Animated.View style={[styles.overlay, { opacity: overlayOpacity }]}>
          <TouchableOpacity style={StyleSheet.absoluteFill} onPress={toggleChat} activeOpacity={1} />
        </Animated.View>
      )}

      {/* Chat Panel */}
      <Animated.View
        style={[
          styles.chatContainer,
          {
            transform: [{ translateY: chatTranslateY }],
            opacity: chatOpacity,
          },
        ]}
        pointerEvents={isOpen ? 'auto' : 'none'}
      >
        {/* Header */}
        <LinearGradient colors={['#2E7D32', '#43A047']} start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }} style={styles.chatHeader}>
          <View style={styles.headerLeft}>
            <View style={styles.botAvatar}>
              <Text style={styles.botAvatarText}>🌱</Text>
            </View>
            <View>
              <Text style={styles.headerTitle}>Farm2Table AI</Text>
              <View style={styles.onlineStatus}>
                <View style={styles.onlineDot} />
                <Text style={styles.onlineText}>Online</Text>
              </View>
            </View>
          </View>
          <View style={styles.headerActions}>
            <TouchableOpacity onPress={handleClearChat} style={styles.headerBtn}>
              <Icon name="delete-outline" size={20} color="#FFFFFF" />
            </TouchableOpacity>
            <TouchableOpacity onPress={toggleChat} style={styles.headerBtn}>
              <Icon name="close" size={20} color="#FFFFFF" />
            </TouchableOpacity>
          </View>
        </LinearGradient>

        {/* Messages */}
        <KeyboardAvoidingView
          style={styles.chatBody}
          behavior={Platform.OS === 'ios' ? 'padding' : undefined}
          keyboardVerticalOffset={100}
        >
          <ScrollView
            ref={scrollViewRef}
            style={styles.messagesContainer}
            contentContainerStyle={styles.messagesContent}
            showsVerticalScrollIndicator={false}
            onContentSizeChange={() => scrollViewRef.current?.scrollToEnd({ animated: true })}
          >
            {messages.map((msg) => (
              <View
                key={msg.id}
                style={[
                  styles.messageBubbleWrapper,
                  msg.isBot ? styles.botBubbleWrapper : styles.userBubbleWrapper,
                ]}
              >
                {msg.isBot && (
                  <View style={styles.msgAvatar}>
                    <Text style={{ fontSize: 14 }}>🌱</Text>
                  </View>
                )}
                <View
                  style={[
                    styles.messageBubble,
                    msg.isBot ? styles.botBubble : styles.userBubble,
                    msg.isError && styles.errorBubble,
                  ]}
                >
                  <Text style={[styles.messageText, msg.isBot ? styles.botText : styles.userText]}>
                    {msg.text}
                  </Text>
                  <Text style={[styles.timestamp, msg.isBot ? styles.botTimestamp : styles.userTimestamp]}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </Text>
                </View>
              </View>
            ))}

            {isLoading && (
              <View style={[styles.messageBubbleWrapper, styles.botBubbleWrapper]}>
                <View style={styles.msgAvatar}>
                  <Text style={{ fontSize: 14 }}>🌱</Text>
                </View>
                <View style={[styles.messageBubble, styles.botBubble, styles.typingBubble]}>
                  <View style={styles.typingDots}>
                    <TypingDot delay={0} />
                    <TypingDot delay={200} />
                    <TypingDot delay={400} />
                  </View>
                </View>
              </View>
            )}

            {/* Quick Replies (show only when few messages) */}
            {messages.length <= 2 && !isLoading && (
              <View style={styles.quickReplies}>
                {quickReplies.map((reply, i) => (
                  <TouchableOpacity
                    key={i}
                    style={styles.quickReplyButton}
                    onPress={() => {
                      setInputText(reply);
                    }}
                  >
                    <Text style={styles.quickReplyText}>{reply}</Text>
                  </TouchableOpacity>
                ))}
              </View>
            )}
          </ScrollView>

          {/* Input Area */}
          <View style={styles.inputArea}>
            <View style={styles.inputWrapper}>
              <TextInput
                style={styles.textInput}
                placeholder="Ask anything..."
                placeholderTextColor="#9E9E9E"
                value={inputText}
                onChangeText={setInputText}
                onSubmitEditing={handleSend}
                returnKeyType="send"
                multiline
                maxLength={500}
              />
              <TouchableOpacity
                onPress={handleSend}
                style={[styles.sendButton, (!inputText.trim() || isLoading) && styles.sendButtonDisabled]}
                disabled={!inputText.trim() || isLoading}
              >
                <LinearGradient
                  colors={inputText.trim() && !isLoading ? ['#2E7D32', '#43A047'] : ['#C8E6C9', '#C8E6C9']}
                  style={styles.sendGradient}
                >
                  <Icon name="send" size={18} color="#FFFFFF" />
                </LinearGradient>
              </TouchableOpacity>
            </View>
            <Text style={styles.poweredBy}>Powered by Gemini AI ✨</Text>
          </View>
        </KeyboardAvoidingView>
      </Animated.View>

      {/* Floating Action Button */}
      <TouchableOpacity onPress={toggleChat} activeOpacity={0.8} style={styles.fabContainer}>
        <Animated.View style={[styles.fabPulse, { transform: [{ scale: pulseAnim }] }]} />
        <Animated.View style={[styles.fab, { transform: [{ scale: fabScale }] }]}>
          <LinearGradient colors={['#2E7D32', '#43A047']} style={styles.fabGradient}>
            <Icon name={isOpen ? 'close' : 'robot-happy-outline'} size={26} color="#FFFFFF" />
          </LinearGradient>
        </Animated.View>
      </TouchableOpacity>
    </View>
  );
}

// Typing indicator dot animation
function TypingDot({ delay }) {
  const anim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    const animation = Animated.loop(
      Animated.sequence([
        Animated.delay(delay),
        Animated.timing(anim, { toValue: 1, duration: 400, useNativeDriver: true }),
        Animated.timing(anim, { toValue: 0, duration: 400, useNativeDriver: true }),
      ])
    );
    animation.start();
    return () => animation.stop();
  }, []);

  return (
    <Animated.View
      style={[
        styles.typingDot,
        {
          opacity: anim.interpolate({ inputRange: [0, 1], outputRange: [0.3, 1] }),
          transform: [{ translateY: anim.interpolate({ inputRange: [0, 1], outputRange: [0, -4] }) }],
        },
      ]}
    />
  );
}

